cds-views-029.codeExamples:
-- Layer 1: Interface View (EKKO + EKPO join)
@AbapCatalog.sqlViewName: 'ZI_PO_HEADER_SQL'
@AbapCatalog.compiler.compareFilter: true
@AccessControl.authorizationCheck: #NOT_REQUIRED
@VDM.viewType: #BASIC
define view ZI_PO_HEADER
  as select from ekko
  association [0..*] to ekpo as _Items
    on $projection.Ebeln = _Items.Ebeln
{
  key ebeln as Ebeln,
      lifnr as Vendor,
      ekgrp as PurchasingGroup,
      _Items  -- association exposed
}

-- Layer 2: Consumption View (Fiori ready)
@AbapCatalog.sqlViewName: 'ZC_PO_HEADER_SQL'
@AccessControl.authorizationCheck: #CHECK
@VDM.viewType: #CONSUMPTION
@UI.headerInfo: { typeName: 'Purchase Order' }
define view ZC_PO_HEADER
  as select from ZI_PO_HEADER
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key Ebeln,

  @UI.lineItem: [{ position: 20 }]
  Vendor,

  @UI.lineItem: [{ position: 30 }]
  PurchasingGroup
}

-- Layer 3: DCL (PFCG based)
@MappingRole: true
define role ZC_PO_HEADER
{
  grant select on ZC_PO_HEADER
    where (PurchasingGroup) =
      aspect pfcg_auth(M_BEST_EKG, EKGRP, ACTVT = '03');
}

