define role ZC_PO_HEADER
{
  grant select on ZC_PO_HEADER
    where (PurchasingGroup) =
      aspect pfcg_auth(
        M_BEST_EKG,    -- auth object
        EKGRP,         -- field mapping (CDS field to auth-object field)
        ACTVT = '03'   -- literal restriction for activity
      );
}

@VDM.viewType: #CONSUMPTION
@UI.headerInfo: {
  typeName: 'Purchase Order',
  typeNamePlural: 'Purchase Orders'
}
define view ZC_PO_HEADER as select from ZI_PO_HEADER
{
  @UI.lineItem: [{ position: 10, label: 'PO Number' }]
  @UI.selectionField: [{ position: 10 }]
  key Ebeln,

  @UI.lineItem: [{ position: 20, label: 'Vendor' }]
  Vendor
}

